func (q *Queries) GetUserPositionIDs(ctx context.Context, arg GetUserPositionIDsParams) ([]uuid.UUID, error) {
	rows, err := q.db.Query(ctx, getUserPositionIDs, arg.CompanyID, arg.UserID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []uuid.UUID{}
	for rows.Next() {
		var position_id uuid.UUID
		if err := rows.Scan(&position_id); err != nil {
			return nil, err
		}
		items = append(items, position_id)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

